\mathrm{E}[(x_{t+1}-x^*)^2] &amp;amp; = \mathbb{E}[\mathbb{E}[(x_{t+1}-x^*)^2\big | x_t]]\\
&amp;amp;\leq (1-2\eta\lambda)^2 \mathbb{E}[(x^*-x_t)^2]+\frac{4\lambda V\eta^3}{l}
\end{aligned}
